sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    /**
    GEM/Nguyenlh - 14.05.2026:
    TAM/Sprint 3/Story TAM_45
    When field changes, configure acceptance criteria handling:
    Check if the input is a number; if not, clear the field.
    */

    if (isLoading || newValue === '') {
        return;
    }
	// Defines a Regular Expression to validate Vietnamese phone formats:
    // ^      : Start of the string
    // (0[3|5|7|8|9]) : Must start with 0, followed by 3, 5, 7, 8, or 9
    // +      : Matches the previous group (the prefix)
    // ([0-9]{8}) : Must be followed by exactly 8 digits (totaling 10 digits)
    // $      : End of the string
    var regexp = /^(0[3|5|7|8|9])+([0-9]{8})$/;
    if (!regexp.test(newValue)) {// Tests if the 'newValue' entered by the user fails the Regex pattern
        g_form.setValue('u_phone_number', ''); // If the value is invalid, clear the 'u_phone_number' field
    }

}
